# --- 3. HELPER FUNCTIONS ---
def apply_table_style(tbl):
    """Applies the dark theme and custom highlights to the summary table."""
    for (r, c), cell in tbl.get_celld().items():
        cell.set_edgecolor("#444b5a")
        cell.set_facecolor(color_bg)
        if r == 0: 
            cell.set_facecolor("#1f2937") # Header row
        if c == 2 and r > 0: 
            cell.get_text().set_color(color_pink) 
        if r == 1 and c < 2: 
            cell.get_text().set_color(color_heads) 
        if r == 2 and c < 2: 
            cell.get_text().set_color(color_tails)

# --- 4. DATA PROCESSING (HIDDEN FROM PLOTTING) ---
all_h_global, all_t_global = [], []

for coin in raw_data:
    h_list = [item for sublist in raw_data[coin]["heads_groups"] for item in sublist]
    t_list = [item for sublist in raw_data[coin]["tails_groups"] for item in sublist]
    all_h_global.extend(h_list)
    all_t_global.extend(t_list)

# --- 5. RENDER ONLY THE COMBINED TOTAL ---
if all_h_global:
    h_cum_g = np.cumsum(all_h_global)
    t_cum_g = np.cumsum(all_t_global)
    final_h_g, final_t_g = h_cum_g[-1], t_cum_g[-1]
    grand_total = len(all_h_global)

    fig_final, ax_g = plt.subplots(figsize=(14, 9))
    
    # Plotting Total Lines
    ax_g.plot(h_cum_g, color=color_heads, linewidth=3, 
              label=f"Total Heads: {final_h_g} ({(final_h_g/grand_total)*100:.1f}%)")
    ax_g.plot(t_cum_g, color=color_tails, linewidth=3, 
              label=f"Total Tails: {final_t_g} ({(final_t_g/grand_total)*100:.1f}%)")

    ax_g.set_title('Canvas H & T (Combined Overall Total)', fontsize=22, fontweight='bold', pad=25)
    ax_g.legend(loc='upper left', fontsize=12, facecolor='#1a222f', edgecolor=color_grid)
    ax_g.set_xlabel("Total Toss # (Aggregated Across All Classes)")
    ax_g.set_ylabel("Cumulative Count")
    ax_g.grid(True, alpha=0.2)

    # Summary Table
    g_data = [
        ["Outcome", "Count", "Probability"], 
        ["Heads (H)", f"{final_h_g}", f"{(final_h_g/grand_total)*100:.1f}%"], 
        ["Tails (T)", f"{final_t_g}", f"{(final_t_g/grand_total)*100:.1f}%"], 
        ["Total", f"{grand_total}", "100.0%"]
    ]
    
    g_tbl = ax_g.table(cellText=g_data, loc='bottom', bbox=[0.15, -0.45, 0.7, 0.3], cellLoc='center')
    apply_table_style(g_tbl)

    plt.subplots_adjust(bottom=0.35) 
    
    
    
    plt.show()